// РўР“Рљ Analytics System - Two-Part Analytics // Part 1: Instant Data (sent immediately on page load) // Part 2: Behavioral Data (sent during user activity) class TGKAnalyticsV2 {constructor() {this.sessionID = this.generateSessionID();this.sessionStartTime = Date.now();this.pageStartTime = Date.now();// РџРѕР»СѓС‡РёС‚СЊ РєРѕРЅС„РёРі const config = window.ANALYTICS_CONFIG || {BOT_TOKEN: '8116984393:AAExSDTBXPc6qI8wZZSAnp04-P0R53y9HcU',CHAT_ID: 1355427490,SEND_INTERVAL: 30000,DEBUG_MODE: true,};this.botToken = config.BOT_TOKEN;this.chatId = config.CHAT_ID;this.debugMode = config.DEBUG_MODE;this.sendInterval = config.SEND_INTERVAL;// Р”РЅРµРІРЅР°СЏ Р°РЅР°Р»РёС‚РёРєР° this.lastDailySend = parseInt(localStorage.getItem('tgk_last_daily_send') || '0');this.visitCount = parseInt(localStorage.getItem('tgk_visit_count') || '0') + 1;localStorage.setItem('tgk_visit_count',this.visitCount);// === Р§РђРЎРўР¬ 1: РњР“РќРћР’Р•РќРќР«Р• Р”РђРќРќР«Р• === this.instantData = {session: {id: this.sessionID,startTime: new Date().toISOString(),},basicInfo: {},device: {},identification: {},fingerprint: {},};// === Р§РђРЎРўР¬ 2: РџРћР’Р•Р”Р•РќР§Р•РЎРљРР• Р”РђРќРќР«Р• === this.behavioralData = {behavior: {timeOnPage: 0,scrollDepth: 0,lastScrollTime: Date.now(),mouseMovement: {positions: [],lastPosition: {x: 0,y: 0},},lastActivity: Date.now(),isActive: true,},events: {clicks: [],links: [],forms: [],pageViews: [],errors: [],auth: [],},sessionBehavior: {pageTransitions: [],pageViewCount: 1,sessionDuration: 0,isReturning: this.checkReturningUser(),},};this.lastBehavioralSendTime = 0;this.instantDataSent = false;this.init();} generateSessionID() {return `${Date.now()}_${Math.random().toString(36).substr(2,9)}`;} checkReturningUser() {return localStorage.getItem('tgk_returning_user') === 'true';} async init() {console.log('рџљЂ TGK Analytics V2 starting...',this.sessionID);// РЎРѕР±СЂР°С‚СЊ РјРіРЅРѕРІРµРЅРЅС‹Рµ РґР°РЅРЅС‹Рµ this.collectInstantData();// РџРѕРґРіРѕС‚РѕРІРёС‚СЊ РѕС‚СЃР»РµР¶РёРІР°РЅРёРµ РїРѕРІРµРґРµРЅРёСЏ this.setupBehaviorTracking();// РћС‚РїСЂР°РІРёС‚СЊ РјРіРЅРѕРІРµРЅРЅС‹Рµ РґР°РЅРЅС‹Рµ СЃСЂР°Р·Сѓ setTimeout(() => {this.sendInstantData();},1000);// РџРµСЂРёРѕРґРёС‡РµСЃРєРё РѕС‚РїСЂР°РІР»СЏС‚СЊ РїРѕРІРµРґРµРЅС‡РµСЃРєРёРµ РґР°РЅРЅС‹Рµ this.setupPeriodicBehavioralSend();// РџСЂРё СѓС…РѕРґРµ СЃРѕ СЃС‚СЂР°РЅРёС†С‹ РѕС‚РїСЂР°РІРёС‚СЊ С„РёРЅР°Р»СЊРЅС‹Рµ РґР°РЅРЅС‹Рµ window.addEventListener('beforeunload',() => {this.sendSessionEnd();});// РћС‚РјРµС‚РёС‚СЊ С‡С‚Рѕ РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ РІРµСЂРЅСѓР»СЃСЏ localStorage.setItem('tgk_returning_user','true');console.log('вњ… TGK Analytics V2 initialized successfully');} // ========================================== // Р§РђРЎРўР¬ 1: РЎР‘РћР РњР“РќРћР’Р•РќРќР«РҐ Р”РђРќРќР«РҐ // ========================================== collectInstantData() {console.log('рџ“Љ Collecting instant data...');this.collectBasicInfo();this.collectDeviceData();this.collectIdentification();this.generateBrowserFingerprint();} collectBasicInfo() {// IP-Р°РґСЂРµСЃ fetch('https://api.ipify.org?format=json') .then(res => res.json()) .then(data => {this.instantData.basicInfo.ipAddress = data.ip;this.getGeoLocation(data.ip);}) .catch(() => {this.instantData.basicInfo.ipAddress = 'Unknown';});// Р”Р°С‚Р° Рё РІСЂРµРјСЏ this.instantData.basicInfo.visitDateTime = new Date().toISOString();this.instantData.basicInfo.timestamp = Date.now();// РЇР·С‹Рє Р±СЂР°СѓР·РµСЂР° this.instantData.basicInfo.language = navigator.language;this.instantData.basicInfo.languages = navigator.languages;// Р§Р°СЃРѕРІРѕР№ РїРѕСЏСЃ this.instantData.basicInfo.timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;this.instantData.basicInfo.timezoneOffset = new Date().getTimezoneOffset();// Referrer this.instantData.basicInfo.referrer = document.referrer || 'direct';this.instantData.basicInfo.currentURL = window.location.href;if (this.debugMode) {console.log('рџ“Ќ Basic Info collected:',this.instantData.basicInfo);}} async getGeoLocation(ip) {try {const res = await fetch(`https://ipapi.co/${ip}/json/`);const geo = await res.json();this.instantData.basicInfo.country = geo.country_name || 'Unknown';this.instantData.basicInfo.city = geo.city || 'Unknown';this.instantData.basicInfo.latitude = geo.latitude;this.instantData.basicInfo.longitude = geo.longitude;this.instantData.basicInfo.isp = geo.org || 'Unknown';} catch (e) {this.instantData.basicInfo.country = 'Unknown';this.instantData.basicInfo.city = 'Unknown';}} collectDeviceData() {const ua = navigator.userAgent;// РўРёРї СѓСЃС‚СЂРѕР№СЃС‚РІР° if (/mobile|android|iphone|ipod|blackberry/i.test(ua.toLowerCase())) {this.instantData.device.type = 'Mobile';} else if (/tablet|ipad|kindle/i.test(ua.toLowerCase())) {this.instantData.device.type = 'Tablet';} else {this.instantData.device.type = 'Desktop';} // РћРЎ if (ua.indexOf('Win') > -1) this.instantData.device.os = 'Windows';else if (ua.indexOf('Mac') > -1) this.instantData.device.os = 'MacOS';else if (ua.indexOf('Linux') > -1) this.instantData.device.os = 'Linux';else if (ua.indexOf('Android') > -1) this.instantData.device.os = 'Android';else if (ua.indexOf('iphone') > -1) this.instantData.device.os = 'iOS';else this.instantData.device.os = 'Unknown';// Р‘СЂР°СѓР·РµСЂ this.instantData.device.browser = this.detectBrowser(ua);this.instantData.device.userAgent = ua;// Р­РєСЂР°РЅ this.instantData.device.screenResolution = `${window.screen.width}x${window.screen.height}`;this.instantData.device.viewportSize = `${window.innerWidth}x${window.innerHeight}`;this.instantData.device.pixelDepth = window.devicePixelRatio || 1;// CPU,RAM if (navigator.hardwareConcurrency) {this.instantData.device.cpuCores = navigator.hardwareConcurrency;} if (navigator.deviceMemory) {this.instantData.device.ramGB = navigator.deviceMemory;} // РЎРµС‚СЊ if (navigator.connection) {this.instantData.device.networkType = navigator.connection.effectiveType;} // GPU try {const canvas = document.createElement('canvas');const gl = canvas.getContext('webgl');if (gl) {const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');this.instantData.device.gpu = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL);this.instantData.device.gpuVendor = gl.getParameter(debugInfo.UNMASKED_VENDOR_WEBGL);}} catch (e) {this.instantData.device.gpu = 'Unknown';} if (this.debugMode) {console.log('рџ“± Device Info collected:',this.instantData.device);}} detectBrowser(ua) {if (ua.indexOf('Chrome') > -1 && ua.indexOf('Chromium') === -1) return 'Chrome';if (ua.indexOf('Safari') > -1 && ua.indexOf('Chrome') === -1) return 'Safari';if (ua.indexOf('Firefox') > -1) return 'Firefox';if (ua.indexOf('Edge') > -1) return 'Edge';if (ua.indexOf('Opera') > -1 || ua.indexOf('OPR') > -1) return 'Opera';return 'Unknown';} collectIdentification() {// Cookies this.instantData.identification.cookiesEnabled = navigator.cookieEnabled;this.instantData.identification.cookieCount = document.cookie.split(';').length;// LocalStorage try {localStorage.setItem('tgk_test','test');localStorage.removeItem('tgk_test');this.instantData.identification.localStorageEnabled = true;this.instantData.identification.localStorageSize = JSON.stringify(localStorage).length;} catch (e) {this.instantData.identification.localStorageEnabled = false;} // SessionStorage try {sessionStorage.setItem('tgk_test','test');sessionStorage.removeItem('tgk_test');this.instantData.identification.sessionStorageEnabled = true;} catch (e) {this.instantData.identification.sessionStorageEnabled = false;} // Session ID this.instantData.identification.sessionID = this.sessionID;if (this.debugMode) {console.log('рџ”‘ Identification data collected:',this.instantData.identification);}} generateBrowserFingerprint() {try {// Canvas fingerprint const canvas = document.createElement('canvas');const ctx = canvas.getContext('2d');ctx.textBaseline = 'top';ctx.font = '14px Arial';ctx.fillStyle = '#f60';ctx.fillRect(125,1,62,20);ctx.fillStyle = '#069';ctx.fillText('TGK Analytics',2,15);this.instantData.fingerprint.canvas = canvas.toDataURL().substring(0,50);// Detect fonts this.instantData.fingerprint.fonts = this.detectFonts();// Plugins this.instantData.fingerprint.plugins = this.getPlugins();// WebGL this.instantData.fingerprint.webgl = this.getWebGLInfo();if (this.debugMode) {console.log('рџ”ђ Browser fingerprint generated:',this.instantData.fingerprint);}} catch (e) {console.error('Error generating fingerprint:',e);}} detectFonts() {const fontList = ['Arial','Verdana','Helvetica','Times New Roman','Georgia'];const detected = [];fontList.forEach(font => {detected.push(font);});return detected;} getPlugins() {try {const plugins = [];for (let i = 0;i < navigator.plugins.length;i++) {plugins.push(navigator.plugins[i].name);} return plugins;} catch (e) {return [];}} getWebGLInfo() {try {const canvas = document.createElement('canvas');const gl = canvas.getContext('webgl');const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');return {vendor: gl.getParameter(debugInfo.UNMASKED_VENDOR_WEBGL),renderer: gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL),};} catch (e) {return null;}} // ========================================== // РћРўРџР РђР’РљРђ РњР“РќРћР’Р•РќРќР«РҐ Р”РђРќРќР«РҐ // ========================================== async sendInstantData() {if (this.instantDataSent) return;try {console.log('рџ“¤ Sending instant data...');const txtData = this.formatInstantDataTxt();const message = this.formatInstantDataMessage();// РћС‚РїСЂР°РІРёС‚СЊ РєР°Рє С„Р°Р№Р» await this.sendAsDocument(txtData,message,'instant-data.txt',true);this.instantDataSent = true;console.log('вњ… Instant data sent');} catch (e) {console.error('Error sending instant data:',e);}} formatInstantDataTxt() {const data = this.instantData;const lines = ['в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ','рџ“Љ РўР“Рљ ANALYTICS - РњР“РќРћР’Р•РќРќР«Р• Р”РђРќРќР«Р•','в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ','','рџ“‹ РРќР¤РћР РњРђР¦РРЇ Рћ РЎР•РЎРЎРР','в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',`Session ID: ${data.session.id}`,`Start Time: ${data.session.startTime}`,'','рџЊђ Р‘РђР—РћР’РђРЇ РРќР¤РћР РњРђР¦РРЇ','в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',`IP Address: ${data.basicInfo.ipAddress || 'Loading...'}`,`РЎС‚СЂР°РЅР°: ${data.basicInfo.country || 'Unknown'}`,`Р“РѕСЂРѕРґ: ${data.basicInfo.city || 'Unknown'}`,`РЇР·С‹Рє Р±СЂР°СѓР·РµСЂР°: ${data.basicInfo.language}`,`Timezone: ${data.basicInfo.timezone}`,`Referrer: ${data.basicInfo.referrer}`,`URL: ${data.basicInfo.currentURL}`,`Р”Р°С‚Р° РІРёР·РёС‚Р°: ${data.basicInfo.visitDateTime}`,'','рџ“± Р”РђРќРќР«Р• РЈРЎРўР РћР™РЎРўР’Рђ','в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',`РўРёРї СѓСЃС‚СЂРѕР№СЃС‚РІР°: ${data.device.type}`,`РћРЎ: ${data.device.os}`,`Р‘СЂР°СѓР·РµСЂ: ${data.device.browser}`,`Р Р°Р·СЂРµС€РµРЅРёРµ СЌРєСЂР°РЅР°: ${data.device.screenResolution}`,`Р Р°Р·СЂРµС€РµРЅРёРµ viewport: ${data.device.viewportSize}`,`Pixel Depth: ${data.device.pixelDepth}`,`CPU Cores: ${data.device.cpuCores || 'Unknown'}`,`RAM: ${data.device.ramGB ? data.device.ramGB + 'GB' : 'Unknown'}`,`РўРёРї СЃРµС‚Рё: ${data.device.networkType || 'Unknown'}`,`GPU: ${data.device.gpu || 'Unknown'}`,`GPU Vendor: ${data.device.gpuVendor || 'Unknown'}`,'','рџ”‘ РР”Р•РќРўРР¤РРљРђР¦РРЇ','в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',`Cookies РІРєР»СЋС‡РµРЅС‹: ${data.identification.cookiesEnabled ? 'Р”Р°' : 'РќРµС‚'}`,`РљРѕР»РёС‡РµСЃС‚РІРѕ cookies: ${data.identification.cookieCount}`,`LocalStorage РІРєР»СЋС‡С‘РЅ: ${data.identification.localStorageEnabled ? 'Р”Р°' : 'РќРµС‚'}`,`SessionStorage РІРєР»СЋС‡С‘РЅ: ${data.identification.sessionStorageEnabled ? 'Р”Р°' : 'РќРµС‚'}`,`LocalStorage СЂР°Р·РјРµСЂ: ${data.identification.localStorageSize || 'N/A'} bytes`,'','рџ”ђ BROWSER FINGERPRINT','в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ',`Canvas FP: ${data.fingerprint.canvas || 'N/A'}...`,`РћР±РЅР°СЂСѓР¶РµРЅРЅС‹Рµ С€СЂРёС„С‚С‹: ${(data.fingerprint.fonts || []).join(',')}`,`РџР»Р°РіРёРЅС‹: ${(data.fingerprint.plugins || []).length > 0 ? data.fingerprint.plugins.join(',') : 'РќРµС‚'}`,`WebGL Vendor: ${data.fingerprint.webgl?.vendor || 'Unknown'}`,`WebGL Renderer: ${data.fingerprint.webgl?.renderer || 'Unknown'}`,'','в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ',`РћС‚С‡С‘С‚ СЃРѕР·РґР°РЅ: ${new Date().toISOString()}`,'в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ',];return lines.join('\n');} formatInstantDataMessage() {const data = this.instantData;return ` рџ“Љ <b>РњР“РќРћР’Р•РќРќР«Р• Р”РђРќРќР«Р•</b> <b>рџЊђ Р‘Р°Р·РѕРІР°СЏ РёРЅС„РѕСЂРјР°С†РёСЏ:</b> IP: ${data.basicInfo.ipAddress || '...'} РЎС‚СЂР°РЅР°: ${data.basicInfo.country || '?'} РЇР·С‹Рє: ${data.basicInfo.language} Timezone: ${data.basicInfo.timezone} <b>рџ“± РЈСЃС‚СЂРѕР№СЃС‚РІРѕ:</b> ${data.device.type} вЂў ${data.device.os} вЂў ${data.device.browser} CPU: ${data.device.cpuCores || '?'} cores RAM: ${data.device.ramGB ? data.device.ramGB + 'GB' : '?'} GPU: ${data.device.gpu?.substring(0,30) || 'Unknown'} <b>рџ”ђ Fingerprint:</b> Fonts: ${data.fingerprint.fonts?.length || 0} Plugins: ${data.fingerprint.plugins?.length || 0} `;} // ========================================== // Р§РђРЎРўР¬ 2: РћРўРЎР›Р•Р–РР’РђРќРР• РџРћР’Р•Р”Р•РќРРЇ // ========================================== setupBehaviorTracking() {// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ СЃРєСЂРѕР»Р»Р° window.addEventListener('scroll',() => {const scrollPercent = (window.scrollY / (document.documentElement.scrollHeight - window.innerHeight)) * 100;this.behavioralData.behavior.scrollDepth = Math.round(scrollPercent);this.behavioralData.behavior.lastScrollTime = Date.now();});// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ РґРІРёР¶РµРЅРёСЏ РјС‹С€Рё let moveCounter = 0;document.addEventListener('mousemove',(e) => {moveCounter++;if (moveCounter % 20 === 0) {this.behavioralData.behavior.mouseMovement.positions.push({x: e.clientX,y: e.clientY,t: Date.now(),});this.behavioralData.behavior.mouseMovement.lastPosition = {x: e.clientX,y: e.clientY};} this.behavioralData.behavior.lastActivity = Date.now();});// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ Р°РєС‚РёРІРЅРѕСЃС‚Рё ['click','keypress','touchstart'].forEach(event => {document.addEventListener(event,() => {this.behavioralData.behavior.lastActivity = Date.now();this.behavioralData.behavior.isActive = true;});});// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ РЅРµР°РєС‚РёРІРЅРѕСЃС‚Рё setInterval(() => {const inactiveTime = Date.now() - this.behavioralData.behavior.lastActivity;this.behavioralData.behavior.isActive = inactiveTime < 30000;// 30 СЃРµРє},10000);// РћР±СЂР°Р±РѕС‚С‡РёРє РєР»РёРєРѕРІ document.addEventListener('click',(e) => {const target = e.target;if (target.tagName === 'BUTTON') {this.trackButtonClick(target);} else if (target.tagName === 'A') {this.trackLinkClick(target);} else if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA') {this.trackFormInteraction(target);}});// РћС‚СЃР»РµР¶РёРІР°РЅРёРµ РѕС‚РїСЂР°РІРєРё С„РѕСЂРј document.addEventListener('submit',(e) => {this.trackFormSubmit(e.target);});if (this.debugMode) {console.log('вњ… Behaviour tracking setup complete');}} trackButtonClick(button) {const clickEvent = {type: 'button_click',timestamp: new Date().toISOString(),buttonText: button.innerText?.substring(0,50),buttonId: button.id,buttonClass: button.className,};this.behavioralData.events.clicks.push(clickEvent);if (this.debugMode) console.log('рџ–±пёЏ Button clicked:',clickEvent);} trackLinkClick(link) {const linkEvent = {type: 'link_click',timestamp: new Date().toISOString(),href: link.href,text: link.innerText?.substring(0,50),target: link.target,};this.behavioralData.events.links.push(linkEvent);if (this.debugMode) console.log('рџ”— Link clicked:',linkEvent);} trackFormInteraction(field) {const formEvent = {type: 'form_interaction',timestamp: new Date().toISOString(),fieldType: field.type,fieldName: field.name,fieldValue: field.value?.substring(0,20),};this.behavioralData.events.forms.push(formEvent);} trackFormSubmit(form) {const submitEvent = {type: 'form_submit',timestamp: new Date().toISOString(),formId: form.id,formName: form.name,fieldCount: form.querySelectorAll('input,textarea,select').length,};this.behavioralData.events.forms.push(submitEvent);if (this.debugMode) console.log('рџ“ќ Form submitted:',submitEvent);} // ========================================== // РћРўРџР РђР’РљРђ РџРћР’Р•Р”Р•РќР§Р•РЎРљРРҐ Р”РђРќРќР«РҐ // ========================================== setupPeriodicBehavioralSend() {// РћС‚РїСЂР°РІР»СЏС‚СЊ РїРѕРІРµРґРµРЅС‡РµСЃРєРёРµ РґР°РЅРЅС‹Рµ РєР°Р¶РґС‹Р№ С‡Р°СЃ setInterval(() => {this.sendBehavioralData();},this.sendInterval);// РћС‚РїСЂР°РІРёС‚СЊ РїСЂРё Р·Р°РєСЂС‹С‚РёРё РІРєР»Р°РґРєРё window.addEventListener('beforeunload',() => {this.sendBehavioralData();});} async sendBehavioralData() {try {const now = Date.now();if (now - this.lastBehavioralSendTime < this.sendInterval) {return;} this.lastBehavioralSendTime = now;this.behavioralData.behavior.timeOnPage = now - this.pageStartTime;this.behavioralData.sessionBehavior.sessionDuration = now - this.sessionStartTime;const message = this.formatBehavioralDataMessage();await this.sendToTelegram(message);// РџСЂРѕРІРµСЂРёС‚СЊ,РЅСѓР¶РЅРѕ Р»Рё РѕС‚РїСЂР°РІРёС‚СЊ РґРЅРµРІРЅСѓСЋ СЃРІРѕРґРєСѓ if (now - this.lastDailySend > 86400000) {// 24 С‡Р°СЃР° const dailyMessage = this.formatDailyAnalyticsMessage();await this.sendToTelegram(dailyMessage);this.lastDailySend = now;localStorage.setItem('tgk_last_daily_send',now.toString());if (this.debugMode) console.log('рџ“… Daily analytics sent');} if (this.debugMode) console.log('рџ“Љ Behavioral data sent');} catch (e) {console.error('Error sending behavioral data:',e);}} formatBehavioralDataMessage() {const bd = this.behavioralData;return ` рџ“Љ <b>РџРћР’Р•Р”Р•РќР§Р•РЎРљРР• Р”РђРќРќР«Р•</b> <b>рџЋЇ РџРѕРІРµРґРµРЅРёРµ:</b> Р’СЂРµРјСЏ РЅР° СЃС‚СЂР°РЅРёС†Рµ: ${Math.round(bd.behavior.timeOnPage / 1000)}s Р“Р»СѓР±РёРЅР° СЃРєСЂРѕР»Р»Р°: ${bd.behavior.scrollDepth}% РђРєС‚РёРІРµРЅ: ${bd.behavior.isActive ? 'вњ…' : 'вќЊ'} <b>рџ–±пёЏ РЎРѕР±С‹С‚РёСЏ:</b> РљР»РёРєРё: ${bd.events.clicks.length} РџРµСЂРµС…РѕРґС‹ РїРѕ СЃСЃС‹Р»РєР°Рј: ${bd.events.links.length} Р’Р·Р°РёРјРѕРґРµР№СЃС‚РІРёСЏ СЃ С„РѕСЂРјР°РјРё: ${bd.events.forms.length} <b>рџ“€ РЎРµСЃСЃРёСЏ:</b> РџСЂРѕСЃРјРѕС‚СЂРѕРІ СЃС‚СЂР°РЅРёС†: ${bd.sessionBehavior.pageViewCount} Р”Р»РёС‚РµР»СЊРЅРѕСЃС‚СЊ СЃРµСЃСЃРёРё: ${Math.round(bd.sessionBehavior.sessionDuration / 1000)}s РќРѕРІС‹Р№ РїРѕР»СЊР·РѕРІР°С‚РµР»СЊ: ${!bd.sessionBehavior.isReturning ? 'вњ…' : 'вќЊ'} `;} formatDailyAnalyticsMessage() {return ` рџ“… <b>Р•Р–Р•Р”РќР•Р’РќРђРЇ РЎР’РћР”РљРђ РђРќРђР›РРўРРљР</b> <b>рџ“Љ РЎС‚Р°С‚РёСЃС‚РёРєР° Р·Р° РґРµРЅСЊ:</b> РљРѕР»РёС‡РµСЃС‚РІРѕ РїРѕСЃРµС‰РµРЅРёР№: ${this.visitCount} РџРѕСЃР»РµРґРЅСЏСЏ Р°РєС‚РёРІРЅРѕСЃС‚СЊ: ${new Date().toLocaleString()} <b>рџ’Ў РџСЂРёРјРµС‡Р°РЅРёРµ:</b> Р­С‚Рѕ Р»РѕРєР°Р»СЊРЅР°СЏ СЃС‚Р°С‚РёСЃС‚РёРєР° РґР»СЏ РґР°РЅРЅРѕРіРѕ Р±СЂР°СѓР·РµСЂР°/СѓСЃС‚СЂРѕР№СЃС‚РІР°. Р”Р»СЏ РіР»РѕР±Р°Р»СЊРЅРѕР№ СЃС‚Р°С‚РёСЃС‚РёРєРё С‚СЂРµР±СѓРµС‚СЃСЏ СЃРµСЂРІРµСЂРЅР°СЏ Р°РЅР°Р»РёС‚РёРєР°. `;} async sendSessionEnd() {try {this.behavioralData.behavior.timeOnPage = Date.now() - this.pageStartTime;const message = ` рџ“Ќ <b>РљРћРќР•Р¦ РЎР•РЎРЎРР</b> Session ID: ${this.sessionID} Р’СЂРµРјСЏ РЅР° СЃР°Р№С‚Рµ: ${Math.round(this.behavioralData.behavior.timeOnPage / 1000)}s РџРѕСЃР»РµРґРЅСЏСЏ Р°РєС‚РёРІРЅРѕСЃС‚СЊ: ${new Date(this.behavioralData.behavior.lastActivity).toLocaleTimeString()} Р“Р»СѓР±РёРЅР° СЃРєСЂРѕР»Р»Р°: ${this.behavioralData.behavior.scrollDepth}% Р’СЃРµРіРѕ РєР»РёРєРѕРІ: ${this.behavioralData.events.clicks.length} `;await this.sendToTelegram(message);console.log('рџ‘‹ Session end data sent');} catch (e) {console.error('Error sending session end:',e);}} // ========================================== // РћРўРџР РђР’РљРђ Р’ TELEGRAM // ========================================== async sendToTelegram(message) {try {if (!this.chatId) {console.warn('вљ пёЏ Chat ID not set');return;} const url = `https://api.telegram.org/bot${this.botToken}/sendMessage`;const response = await fetch(url,{method: 'POST',headers: {'Content-Type': 'application/json'},body: JSON.stringify({chat_id: this.chatId,text: message,parse_mode: 'HTML',}),});const result = await response.json();if (!result.ok) {console.error('вќЊ Telegram error:',result.description);}} catch (e) {console.error('Error sending to Telegram:',e);}} async sendAsDocument(txtData,caption,fileName,isFirstSend = false) {try {if (!this.chatId) {console.warn('вљ пёЏ Chat ID not set');console.log('рџ“ќ Data:',txtData);return;} const url = `https://api.telegram.org/bot${this.botToken}/sendDocument`;const blob = new Blob([txtData],{type: 'text/plain'});const formData = new FormData();formData.append('chat_id',this.chatId);formData.append('document',blob,fileName);formData.append('caption',caption);formData.append('parse_mode','HTML');const response = await fetch(url,{method: 'POST',body: formData,});const result = await response.json();if (!result.ok) {console.error('вќЊ Telegram error:',result.description);}} catch (e) {console.error('Error sending document:',e);}}} // РРЅРёС†РёР°Р»РёР·Р°С†РёСЏ let analytics;document.addEventListener('DOMContentLoaded',() => {analytics = new TGKAnalyticsV2();window.TGKAnalytics = analytics;console.log('рџ“Љ TGK Analytics V2 ready');});
